/**
 * @generated by @flusk/cli — cli-command recipe
 * CLI command: flusk kill
 */
import { Command } from 'commander';
import chalk from 'chalk';
import { getDb } from '@flusk/resources';

export const killCommand = new Command('kill')
  .description('Emergency kill — disable all alert channels immediately')
  .option('--confirm', 'Skip confirmation prompt')
  .action(async (opts) => {
    if (!opts.confirm) {
      console.log(chalk.yellow('⚠️  This will disable ALL alert channels.'));
      console.log(chalk.yellow('   Re-run with --confirm to proceed.'));
      return;
    }

    const db = getDb();
    const { AlertChannelRepository } = await import('@flusk/resources');
    const channels = AlertChannelRepository.listAlertChannels(db);

    let muted = 0;
    for (const ch of channels) {
      if (ch.enabled) {
        AlertChannelRepository.updateAlertChannel(db, ch.id, { enabled: false });
        muted++;
      }
    }

    console.log(chalk.green(`✅ Kill switch activated — ${muted} channel(s) disabled`));
  });
